type TemplateRLE = { name: string; emoji: string; colors: string[]; rle: string };

function decodeRLE(t: TemplateRLE): (string | null)[][] {
  const flat: (string | null)[] = [];
  for (const tok of t.rle.split(',')) {
    const xIdx = tok.indexOf('x');
    if (xIdx > -1) {
      const val = parseInt(tok.slice(0, xIdx), 10);
      const cnt = parseInt(tok.slice(xIdx + 1), 10);
      const c = val === 0 ? null : t.colors[val - 1];
      for (let i = 0; i < cnt; i++) flat.push(c);
    } else {
      const val = parseInt(tok, 10);
      flat.push(val === 0 ? null : t.colors[val - 1]);
    }
  }
  const grid: (string | null)[][] = [];
  for (let r = 0; r < 32; r++) grid.push(flat.slice(r * 32, r * 32 + 32));
  return grid;
}

